/*
===============================================================================
INSERT DATA - Employees
===============================================================================
Script Purpose:
    This script inserts employee data into the HR Analytics database.
    
Prerequisites:
    - Database HRAnalytics must exist
    - Table employees must be created
    - Departments must be inserted first

Usage:
    Execute this script in SQL Server Management Studio (SSMS)
===============================================================================
*/

USE HRAnalytics;
GO

PRINT 'Inserting employees...';

-- Clear existing employees (if any)
IF EXISTS (SELECT 1 FROM dbo.employees)
BEGIN
    PRINT 'Clearing existing employees...'
    DELETE FROM dbo.employees;
    DBCC CHECKIDENT ('dbo.employees', RESEED, 0);
END;
GO

SET IDENTITY_INSERT dbo.employees ON;

